import { FoldersApi, type ResponsesFolderData } from '@/api';
import { useAuth } from '@/contexts/AuthContext';
import { cn } from '@/utils/cn';
import {
	createEffect,
	createMemo,
	createSignal,
	For,
	type ComponentProps,
} from 'solid-js';
import { Button } from './atoms';

interface FolderComponentProps extends ComponentProps<'div'> {
	folder: ResponsesFolderData;
	selectedFolder: () => string;
	setSelectedFolder: (id: string) => void;
	deleteFolder: (id: string) => void;
	showCreateFolder: (folderBookmarkRefresh: () => void) => void;
	indent?: number;
}

export default function FolderComponent(props: FolderComponentProps) {
	const { folder, selectedFolder, setSelectedFolder, deleteFolder, indent } =
		props;
	const foldersApi = new FoldersApi();

	const [isFolderOpen, setIsFolderOpen] = createSignal(false);
	createEffect(() => {
		console.log(folder);
	});

	const [children, setChildren] = createSignal<ResponsesFolderData[]>(
		folder.children || [],
	);

	const auth = useAuth();

	const openFolder = async () => {
		if (folder.children && folder.children.length > 0) {
			setIsFolderOpen(!isFolderOpen());
		} else {
			// try to get the folder content from the server
			const response = await foldersApi.getFolders({
				folderId: folder.id || '',
				authorization: `Bearer ${auth.token()}`,
			});
			if (response.success && response.data?.children) {
				console.log(response.data.children);
				setChildren(response.data.children || []);
				setIsFolderOpen(true);
			} else {
				console.error(
					'Failed to get folder content:',
					response.message,
					response.data,
					response.success,
				);
			}
		}
	};

	const renderChildren = () =>
		createMemo(() => {
			if (children() && children().length > 0) {
				return (
					<div class="space-y-4">
						<For each={children()}>
							{(child) => (
								<FolderComponent
									folder={child}
									selectedFolder={selectedFolder}
									setSelectedFolder={setSelectedFolder}
									deleteFolder={deleteFolder}
									indent={indent ? indent + 1 : 1}
									showCreateFolder={props.showCreateFolder}
								/>
							)}
						</For>
						<Button
							variant="secondary"
							onClick={() => {
								props.showCreateFolder(true, () => {
									console.log()
								});
							}}
						>
							Create Bookmark 
						</Button>
					</div>
				);
			}
		}, [children]);

	const childClassName = (): string => {
		let isFolder = '';
		if (folder.id === selectedFolder()) {
			isFolder = 'bg-secondary text-secondary-foreground hover:bg-secondary/80';
		}
		const indentNow = indent ? 'ml-' + indent * 4 : '';
		return cn(
			`flex flex-row items-center py-1 px-2 cursor-pointer bg-primary text-primary-foreground hover:bg-primary/80 rounded-lg
		shadow-md hover:shadow-lg transition-all duration-200 shadow-slate-900/80 ease-in-out space-x-1 justify-between`,
			isFolder,
			indentNow,
		);
	};

	return (
		<>
			<div
				class={childClassName()}
				onClick={() => {
					setSelectedFolder(folder.id || '');
					openFolder();
				}}
			>
				<div
					class={cn(
						'text-secondary bg-secondary-foreground hover:text-secondary-hover-foreground text-xs w-8 h-8 flex items-center justify-center rounded-full',
						folder.id === selectedFolder() &&
							'text-secondary-foreground hover:text-secondary-hover-foreground',
					)}
				>
					<img
						src="http://localhost:60000/assets/svgs/folder.svg"
						class="p-1"
					/>
				</div>

				<div>
					<span class="mr-2 text-base font-bold">{folder.name}</span>
				</div>
				<div class="spcace-x-4 flex flex-row items-center">
					<button
						class="bg-secondary-foreground text-xs w-8 h-8 flex items-center justify-center rounded-full mr-2"
						title="Add Bookmark"
					>
						<img src="http://localhost:60000/assets/svgs/add-link.svg" />
					</button>
					<button
						onClick={(e) => {
							e.stopPropagation();
							deleteFolder(folder.id || '');
						}}
						class="text-error-foreground bg-slate-50 hover:text-red-700 text-xs w-8 h-8 flex items-center justify-center rounded-full"
						title="Delete folder"
					>
						<img
							src="http://localhost:60000/assets/svgs/add-link.svg"
							class="p-2"
						/>
					</button>
				</div>
			</div>
			{isFolderOpen() && renderChildren()}
		</>
	);
}
